// Game loop using setInterval
setInterval(function() {
  // Calculate distance traveled based on time elapsed since last frame
  const deltaTime = Date.now() - lastFrameTimestamp;
  const distanceTraveled = playerSpeed * deltaTime;
  
  // Update player position based on distance traveled
  playerPosition += distanceTraveled;
  
  // Reset last frame timestamp for next iteration
  lastFrameTimestamp = Date.now();
}, 1000 / 60); // 60 frames per second